    .sort((a: any, b: any) => (a.title ?? "").localeCompare(b.title ?? ""))
    .map((t: any) => {
      const { track_singers, track_genres, languages, ...scalar } = t;
      return {
        ...scalar,
        singers:  (track_singers ?? []).map((ts: any) => ts.singers?.name).filter(Boolean) as string[],
