"use client";

import React, { createContext, useContext, useState, useRef, useEffect, useCallback } from "react";

interface PromptOptions {
  title: string;
  description?: string;
  placeholder?: string;
  defaultValue?: string;
  confirmLabel?: string;
}

interface ConfirmOptions {
  title: string;
  description?: string;
  confirmLabel?: string;
  variant?: "danger" | "default";
}

interface DialogState {
  type: "prompt" | "confirm";
  options: PromptOptions | ConfirmOptions;
  resolve: (value: string | boolean | null) => void;
}

interface DialogContextType {
  showPrompt: (options: PromptOptions) => Promise<string | null>;
  showConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

const DialogContext = createContext<DialogContextType | undefined>(undefined);

export function DialogProvider({ children }: { children: React.ReactNode }) {
  const [dialog, setDialog] = useState<DialogState | null>(null);
  const [inputValue, setInputValue] = useState("");
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (dialog?.type === "prompt") {
      const opts = dialog.options as PromptOptions;
      setInputValue(opts.defaultValue ?? "");
      setTimeout(() => inputRef.current?.focus(), 50);
    }
  }, [dialog]);

  const showPrompt = useCallback((options: PromptOptions): Promise<string | null> => {
    return new Promise((resolve) => {
      setDialog({ type: "prompt", options, resolve: resolve as (v: string | boolean | null) => void });
    });
  }, []);

  const showConfirm = useCallback((options: ConfirmOptions): Promise<boolean> => {
    return new Promise((resolve) => {
      setDialog({ type: "confirm", options, resolve: resolve as (v: string | boolean | null) => void });
    });
  }, []);

  const handleConfirm = () => {
    if (!dialog) return;
    if (dialog.type === "prompt") {
      dialog.resolve(inputValue.trim() || null);
    } else {
      dialog.resolve(true);
    }
    setDialog(null);
    setInputValue("");
  };

  const handleCancel = () => {
    if (!dialog) return;
    dialog.resolve(dialog.type === "prompt" ? null : false);
    setDialog(null);
    setInputValue("");
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") handleConfirm();
    if (e.key === "Escape") handleCancel();
  };

  return (
    <DialogContext.Provider value={{ showPrompt, showConfirm }}>
      {children}

      {dialog && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in"
          onClick={handleCancel}
        >
          <div
            className="w-full max-w-sm bg-panel border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden"
            onClick={(e) => e.stopPropagation()}
            onKeyDown={handleKeyDown}
          >
            {/* Icon strip */}
            <div className={`h-1.5 w-full ${
              dialog.type === "confirm" && (dialog.options as ConfirmOptions).variant === "danger"
                ? "bg-pink"
                : "bg-coral"
            }`} />

            <div className="p-6 flex flex-col gap-5">
              {/* Title */}
              <div className="flex flex-col gap-1.5">
                <h3 className="font-display font-bold text-lg text-cream">
                  {dialog.options.title}
                </h3>
                {dialog.options.description && (
                  <p className="text-sm text-muted leading-relaxed">
                    {dialog.options.description}
                  </p>
                )}
              </div>

              {/* Prompt input */}
              {dialog.type === "prompt" && (
                <input
                  ref={inputRef}
                  type="text"
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  placeholder={(dialog.options as PromptOptions).placeholder}
                  className="w-full px-4 py-3 bg-forest-dark border border-white/10 rounded-xl text-cream placeholder-muted focus:outline-none focus:border-coral transition-colors text-sm"
                />
              )}

              {/* Action buttons */}
              <div className="flex gap-3">
                <button
                  onClick={handleCancel}
                  className="flex-1 py-2.5 rounded-xl border border-white/10 text-muted hover:text-cream hover:bg-white/8 text-sm font-semibold transition-colors"
                >
                  Cancel
                </button>
                <button
                  onClick={handleConfirm}
                  disabled={dialog.type === "prompt" && !inputValue.trim()}
                  className={`flex-1 py-2.5 rounded-xl text-sm font-bold transition-all hover:scale-105 active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed disabled:scale-100 ${
                    dialog.type === "confirm" && (dialog.options as ConfirmOptions).variant === "danger"
                      ? "bg-pink text-forest-dark hover:bg-pink/90"
                      : "bg-coral text-forest-dark hover:bg-coral-bright"
                  }`}
                >
                  {dialog.type === "prompt"
                    ? ((dialog.options as PromptOptions).confirmLabel ?? "Create")
                    : ((dialog.options as ConfirmOptions).confirmLabel ?? "Confirm")}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </DialogContext.Provider>
  );
}

export function useDialog() {
  const ctx = useContext(DialogContext);
  if (!ctx) throw new Error("useDialog must be used within DialogProvider");
  return ctx;
}

"use client";

import React, { createContext, useContext, useEffect, useState } from "react";
import { supabase, isSupabaseConfigured } from "../lib/supabase";
import { useAuth } from "./AuthContext";
import { useAudio } from "./AudioContext";
import { RealtimeChannel } from "@supabase/supabase-js";

export interface ActivityState {
  user_id: string;
  display_name: string;
  avatar_url: string;
  current_track_id: string | null;
  current_track_title: string | null;
  current_track_artist: string | null;
  status: "online" | "idle";
}

export interface Message {
  id: string;
  created_at: string;
  sender_id: string;
  receiver_id: string;
  content: string;
}

interface RealtimeContextType {
  onlineUsers: ActivityState[];
  messages: Message[];
  sendMessage: (receiverId: string, content: string) => Promise<void>;
  isChatOpen: boolean;
  setIsChatOpen: (isOpen: boolean) => void;
  activeChatUser: string | null; // ID of the user we are chatting with
  setActiveChatUser: (userId: string | null) => void;
}

const RealtimeContext = createContext<RealtimeContextType | undefined>(undefined);

export const RealtimeProvider = ({ children }: { children: React.ReactNode }) => {
  const { user, profile } = useAuth();
  const { currentTrack } = useAudio();

  const [onlineUsers, setOnlineUsers] = useState<ActivityState[]>([]);
  const [messages, setMessages] = useState<Message[]>([]);
  const [channel, setChannel] = useState<RealtimeChannel | null>(null);

  // Chat UI state
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [activeChatUser, setActiveChatUser] = useState<string | null>(null);

  // Load initial messages when activeChatUser changes
  useEffect(() => {
    if (!user || !activeChatUser || !supabase) return;
    const sb = supabase;

    const fetchMessages = async () => {
      const { data, error } = await sb
        .from("messages")
        .select("*")
        .or(`and(sender_id.eq.${user.id},receiver_id.eq.${activeChatUser}),and(sender_id.eq.${activeChatUser},receiver_id.eq.${user.id})`)
        .order("created_at", { ascending: true })
        .limit(100);

      if (!error && data) {
        setMessages(data);
      }
    };
    fetchMessages();
  }, [user, activeChatUser]);

  useEffect(() => {
    if (!isSupabaseConfigured || !supabase || !user || !profile) return;

    // 1. Setup Presence Channel
    const room = supabase.channel('vibeblower_activity');
    setChannel(room);

    room
      .on('presence', { event: 'sync' }, () => {
        const state = room.presenceState();
        const users: ActivityState[] = [];

        Object.keys(state).forEach((key) => {
          const presences = state[key] as any[];
          if (presences.length > 0) {
            users.push(presences[0] as ActivityState);
          }
        });

        // Filter out ourselves
        setOnlineUsers(users.filter(u => u.user_id !== user.id));
      })
      .subscribe(async (status) => {
        if (status === 'SUBSCRIBED') {
          await room.track({
            user_id: user.id,
            display_name: profile.display_name,
            avatar_url: profile.avatar_url,
            current_track_id: currentTrack?.id || null,
            current_track_title: currentTrack?.title || null,
            current_track_artist: currentTrack?.artist || null,
            status: "online",
          });
        }
      });

    // 2. Setup Postgres Changes for Messages
    const messageListener = supabase
      .channel('public:messages')
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'messages',
          filter: `receiver_id=eq.${user.id}`
        },
        (payload) => {
          const newMessage = payload.new as Message;
          // Add message to state if we are currently chatting with them
          setMessages((prev) => [...prev, newMessage]);
        }
      )
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'messages',
          filter: `sender_id=eq.${user.id}`
        },
        (payload) => {
           const newMessage = payload.new as Message;
           // If we sent it from another tab, add it
           setMessages((prev) => {
             if (!prev.find(m => m.id === newMessage.id)) {
               return [...prev, newMessage];
             }
             return prev;
           });
        }
      )
      .subscribe();

    return () => {
      room.unsubscribe();
      messageListener.unsubscribe();
    };
  }, [user, profile]);

  // Track updates for Presence
  useEffect(() => {
    if (channel && user && profile && channel.state === 'joined') {
      channel.track({
        user_id: user.id,
        display_name: profile.display_name,
        avatar_url: profile.avatar_url,
        current_track_id: currentTrack?.id || null,
        current_track_title: currentTrack?.title || null,
        current_track_artist: currentTrack?.artist || null,
        status: "online",
      });
    }
  }, [currentTrack]);

  const sendMessage = async (receiverId: string, content: string) => {
    if (!supabase || !user) return;

    const { data, error } = await supabase
      .from("messages")
      .insert({
        sender_id: user.id,
        receiver_id: receiverId,
        content: content
      })
      .select()
      .single();

    if (!error && data) {
      setMessages(prev => [...prev, data]);
    }
  };

  return (
    <RealtimeContext.Provider
      value={{
        onlineUsers,
        messages,
        sendMessage,
        isChatOpen,
        setIsChatOpen,
        activeChatUser,
        setActiveChatUser
      }}
    >
      {children}
    </RealtimeContext.Provider>
  );
};

export const useRealtime = () => {
  const context = useContext(RealtimeContext);
  if (context === undefined) {
    throw new Error("useRealtime must be used within a RealtimeProvider");
  }
  return context;
};

